    pink: { shell: "border-pink-200 bg-pink-50/60", number: "from-pink-200 to-rose-300", doodle: "text-pink-400" },
    orange: { shell: "border-orange-200 bg-orange-50/60", number: "from-amber-200 to-orange-300", doodle: "text-orange-400" },
    teal: { shell: "border-teal-200 bg-teal-50/60", number: "from-teal-200 to-emerald-300", doodle: "text-teal-500" },
    zinc: { shell: "border-zinc-200 bg-zinc-50/70", number: "from-zinc-200 to-zinc-300", doodle: "text-zinc-400" },
